.","Public Traction / Activity":"Sólo señales del perfil Hack-Nation y enlaces públicos provistos por el perfil, si existen.","Why Relevant for Founder/Investor Outreach":"Mantener en cola si el perfil tiene señal de founder/CEO/startup y contacto público; no priorizar sin producto verificable.","Risks / Open Questions":"Falta de compañía, producto, dominio y tracción verificable.","Suggested Next Step":"Contactar con pregunta directa: '¿Qué startup estás construyendo ahora, URL/demo y estado de funding?'","US-Based?":"No","Source URLs":"https://www.linkedin.com/in/themanforjob/","Last Evidence Date":"2026-07-19","Research Depth":"Hack-Nation profile only"}}]$json$::jsonb) as record(
    "sourceUserId" uuid,
    "fullName" text,
    "displayName" text,
    "publicProfileUrl" text,
    "university" text,
    "fieldOfStudy" text,
    "academicDegree" text,
    "professionalSituation" text,
    "tagline" text,
    "city" text,
    "country" text,
    "githubUrl" text,
    "linkedinUrl" text,
    "sourceCapturedAt" timestamptz,
    "sourceRecordId" text,
    "priorityTier" text,
    "outreachScore" smallint,
    "confidence" text,
    "evidenceStatus" text,
    "startupSignals" text[],
    "profileCompleteness" smallint,
    "companyName" text,
    "companyUrl" text,
    "sector" text,
    "investmentThesis" text,
    "researchRisks" text,
    "nextStep" text,
    "sourceUrls" text[],
    "researchResult" jsonb
  )
), upserted_participants as (
  insert into public.hack_nation_participants (
    source_user_id, full_name, display_name, public_profile_url,
    university, field_of_study, academic_degree, professional_situation, tagline,
    city, country, github_url, linkedin_url, source_payload, source_captured_at
  )
  select
    "sourceUserId", "fullName", "displayName", "publicProfileUrl",
    university, "fieldOfStudy", "academicDegree", "professionalSituation", tagline,
    city, country, "githubUrl", "linkedinUrl", "researchResult", "sourceCapturedAt"
  from source_records
  on conflict (source_user_id) do update set
    full_name = excluded.full_name,
    display_name = excluded.display_name,
    public_profile_url = excluded.public_profile_url,
    university = excluded.university,
    field_of_study = excluded.field_of_study,
    academic_degree = excluded.academic_degree,
    professional_situation = excluded.professional_situation,
    tagline = excluded.tagline,
    city = excluded.city,
    country = excluded.country,
    github_url = excluded.github_url,
    linkedin_url = excluded.linkedin_url,
    source_payload = excluded.source_payload,
    source_captured_at = excluded.source_captured_at,
    updated_at = now()
  returning id, source_user_id
)
insert into public.hack_nation_startup_candidates (
  participant_id, startup_signals, profile_completeness, company_name, company_url,
  research_status, research_result, researched_at, source_record_id, priority_tier,
  outreach_score, confidence, evidence_status, sector, investment_thesis, research_risks,
  next_step, source_urls
)
select
  participant.id, record."startupSignals", record."profileCompleteness", record."companyName", record."companyUrl",
  case when record."companyName" is null then 'ambiguous' else 'resolved' end,
  record."researchResult", record."sourceCapturedAt", record."sourceRecordId", record."priorityTier",
  record."outreachScore", record.confidence, record."evidenceStatus", record.sector,
  record."investmentThesis", record."researchRisks", record."nextStep", record."sourceUrls"
from source_records record
join public.hack_nation_participants participant on participant.source_user_id = record."sourceUserId"
on conflict (participant_id) do update set
  startup_signals = excluded.startup_signals,
  profile_completeness = excluded.profile_completeness,
  company_name = excluded.company_name,
  company_url = excluded.company_url,
  research_status = excluded.research_status,
  research_result = excluded.research_result,
  researched_at = excluded.researched_at,
  source_record_id = excluded.source_record_id,
  priority_tier = excluded.priority_tier,
  outreach_score = excluded.outreach_score,
  confidence = excluded.confidence,
  evidence_status = excluded.evidence_status,
  sector = excluded.sector,
  investment_thesis = excluded.investment_thesis,
  research_risks = excluded.research_risks,
  next_step = excluded.next_step,
  source_urls = excluded.source_urls,
  updated_at = now();

with rely_company as (
  insert into public.companies (
    stable_key, name, description, primary_industry, size_band, organization_type,
    location, normalized_domain, linkedin_url
  ) values (
    'rely.business', 'Rely',
    'Software platform for LLC formation, documents, compliance and operations workflows.',
    'Software and IT', '2-10', 'Privately Held', 'Argentina', 'rely.business', null
  )
  on conflict (stable_key) do update set
    name = excluded.name,
    description = excluded.description,
    normalized_domain = excluded.normalized_domain,
    updated_at = now()
  returning id
), rely_founder as (
  insert into public.founders (id, display_name)
  values ('0dce5cc7-0c17-4a70-8adc-f2095d7be937', 'Ignacio Estevo')
  on conflict (id) do update set display_name = excluded.display_name, updated_at = now()
  returning id
), rely_identity as (
  insert into public.founder_identities (
    founder_id, provider, profile_url, username, verification_state, captured_at, raw_payload
  )
  select
    founder.id, 'linkedin', 'https://www.linkedin.com/in/ignacio-estevo/', 'ignacio-estevo',
    'verified', '2026-07-19T00:00:00Z',
    '{"source":"founder_submitted","company":"Rely","relationship":"Co-founder and CTO"}'::jsonb
  from rely_founder founder
  on conflict (profile_url) do update set
    founder_id = excluded.founder_id,
    username = excluded.username,
    verification_state = excluded.verification_state,
    captured_at = excluded.captured_at,
    raw_payload = excluded.raw_payload
  returning id
)
insert into public.company_founders (
  company_id, founder_id, current_title, relationship_state, confidence, resolution_reason
)
select
  company.id, founder.id, 'Co-founder and CTO', 'founder_confirmed', 1.000,
  'Founder-submitted Rely profile with public LinkedIn identity.'
from rely_company company
cross join rely_founder founder
on conflict (company_id, founder_id) do update set
  current_title = excluded.current_title,
  relationship_state = excluded.relationship_state,
  confidence = excluded.confidence,
  resolution_reason = excluded.resolution_reason,
  updated_at = now();
